cadishfile:
example.com, adult.example.com {
    @verified cookie verified_prod
    @adult    host adult.example.com
    classify {age} {
        when @verified -> ok
        when @adult    -> gate
        default        -> open
    }
    @gated classify {age}==gate

    redirect @gated 302 https://verify.example.com/?from={host}

    cache_key method host path {age} {device}

    header X-Age-Class    {classify.age}
    header +X-Forwarded-Host {http.Host}
    header +cache_status  X-Cache

    cache_ttl default ttl 30s grace 5m
}
